package pl.msurvival.keys;
import org.bukkit.*;import org.bukkit.configuration.*;import org.bukkit.configuration.file.YamlConfiguration;import org.bukkit.enchantments.Enchantment;import org.bukkit.entity.Player;import org.bukkit.event.*;import org.bukkit.event.block.Action;import org.bukkit.event.inventory.InventoryClickEvent;import org.bukkit.event.player.PlayerInteractEvent;import org.bukkit.inventory.*;import org.bukkit.inventory.meta.ItemMeta;import org.bukkit.persistence.PersistentDataType;import org.bukkit.plugin.java.JavaPlugin;import java.io.*;import java.util.*;
@SuppressWarnings("deprecation")
public final class MSurvivalKeys extends JavaPlugin implements Listener{
 NamespacedKey keyKey,actionKey;File dataFile;YamlConfiguration data;Random random=new Random();
 public void onEnable(){saveDefaultConfig();loadData();keyKey=new NamespacedKey(this,"key_type");actionKey=new NamespacedKey(this,"action");Bukkit.getPluginManager().registerEvents(this,this);cmds();}
 void cmds(){getCommand("keysmenu").setExecutor((s,c,l,a)->{if(s instanceof Player p)openKeys(p);return true;});getCommand("kits").setExecutor((s,c,l,a)->{if(s instanceof Player p)openKits(p);return true;});getCommand("kit").setExecutor((s,c,l,a)->{if(s instanceof Player p&&a.length>0)openKit(p,norm(a[0]));return true;});getCommand("key").setExecutor((s,c,l,a)->{if(s instanceof Player p&&a.length>=2&&a[0].equalsIgnoreCase("use"))openKit(p,norm(a[1]));return true;});getCommand("keyadmin").setExecutor((s,c,l,a)->{if(!s.hasPermission("msurvivalkeys.admin")){s.sendMessage(msg("no-permission"));return true;}if(a.length>0&&a[0].equalsIgnoreCase("reload")){reloadConfig();s.sendMessage(msg("reload"));return true;}if(a.length<3){s.sendMessage(color("&c/keyadmin <give|item|reset> <gracz> <klucz> [ilosc]"));return true;}String mode=a[0].toLowerCase(Locale.ROOT),pl=a[1],key=norm(a[2]);int amount=a.length>=4?parse(a[3]):1;if(mode.equals("reset")){data.set(path(pl)+".lastWeekly",0L);saveData();return true;}if(!getConfig().contains("keys."+key)){s.sendMessage(color("&cNie ma takiego klucza."));return true;}if(mode.equals("give")){setKeys(pl,key,getKeys(pl,key)+amount);s.sendMessage(msg("admin-give").replace("%key%",key).replace("%player%",pl));return true;}if(mode.equals("item")){Player t=Bukkit.getPlayerExact(pl);if(t==null){s.sendMessage(color("&cGracz offline."));return true;}t.getInventory().addItem(keyItem(key,amount));s.sendMessage(msg("admin-item").replace("%key%",key).replace("%player%",pl));return true;}return true;});}
 @EventHandler public void rc(PlayerInteractEvent e){Action a=e.getAction();if(a!=Action.RIGHT_CLICK_AIR&&a!=Action.RIGHT_CLICK_BLOCK)return;String k=keyFrom(e.getItem());if(k==null)return;e.setCancelled(true);openKit(e.getPlayer(),k);}
 @EventHandler public void gui(InventoryClickEvent e){if(!(e.getWhoClicked() instanceof Player p))return;String t=e.getView().getTitle();boolean kg=t.equals(color(getConfig().getString("gui.keys-title"))), kt=t.equals(color(getConfig().getString("gui.kits-title")));if(!kg&&!kt)return;e.setCancelled(true);ItemStack it=e.getCurrentItem();if(it==null||!it.hasItemMeta())return;String a=it.getItemMeta().getPersistentDataContainer().get(actionKey,PersistentDataType.STRING);if(a==null)return;p.closeInventory();if(a.equals("weekly"))weekly(p);else if(a.startsWith("withdraw:"))withdraw(p,a.substring(9));else if(a.startsWith("kit:"))openKit(p,a.substring(4));}
 void openKeys(Player p){Inventory inv=Bukkit.createInventory(null,54,color(getConfig().getString("gui.keys-title")));fill(inv);inv.setItem(getConfig().getInt("weekly.slot",4),action(mat(getConfig().getString("weekly.material")),getConfig().getString("weekly.name"),weeklyLore(p),"weekly"));int slot=10;ConfigurationSection sec=getConfig().getConfigurationSection("keys");if(sec!=null)for(String k:sec.getKeys(false)){if(slot>=44)break;inv.setItem(slot,action(Material.LIGHTNING_ROD,display(k),List.of("&7Wirtualne: &e"+getKeys(p.getName(),k),"&7Fizyczne: &e"+countPhys(p,k),"","&eKliknij, aby wyjąć 1 do EQ."),"withdraw:"+k));slot++;if(slot==17||slot==26||slot==35)slot+=2;}p.openInventory(inv);}
 void openKits(Player p){Inventory inv=Bukkit.createInventory(null,27,color(getConfig().getString("gui.kits-title")));fill(inv);ConfigurationSection sec=getConfig().getConfigurationSection("kits");if(sec!=null)for(String kit:sec.getKeys(false)){int slot=getConfig().getInt("kits."+kit+".slot",13);String req=getConfig().getString("kits."+kit+".required-key",kit);inv.setItem(slot,action(mat(getConfig().getString("kits."+kit+".material","CHEST")),getConfig().getString("kits."+kit+".name",kit),List.of("&7Wymagany: "+display(req),"&7Masz: &e"+total(p,req),"","&eKliknij, aby otworzyć."),"kit:"+kit));}p.openInventory(inv);}
 void weekly(Player p){long cd=getConfig().getLong("settings.cooldown-seconds")*1000L,last=data.getLong(path(p.getName())+".lastWeekly",0),left=cd-(System.currentTimeMillis()-last);if(last>0&&left>0){p.sendMessage(msg("cooldown").replace("%time%",time(left)));return;}String key=roll("weekly-random");data.set(path(p.getName())+".lastWeekly",System.currentTimeMillis());setKeys(p.getName(),key,getKeys(p.getName(),key)+1);p.sendMessage(msg("claimed").replace("%key%",display(key)));}
 void withdraw(Player p,String key){if(getKeys(p.getName(),key)<=0){p.sendMessage(msg("no-key").replace("%key%",display(key)));return;}setKeys(p.getName(),key,getKeys(p.getName(),key)-1);p.getInventory().addItem(keyItem(key,1));p.sendMessage(msg("withdrawn").replace("%key%",display(key)));}
 void openKit(Player p,String kit){if(blocked(p)){p.sendMessage(msg("blocked"));return;}if(!getConfig().contains("kits."+kit)){if(getConfig().contains("keys."+kit))openKit(p,kit);return;}String req=getConfig().getString("kits."+kit+".required-key",kit);if(!takeKey(p,req)){p.sendMessage(msg("no-key").replace("%key%",display(req)));return;}p.sendTitle(color("&6&lOTWIERANIE KITU"),color(getConfig().getString("kits."+kit+".name",kit)),5,25,5);p.playSound(p.getLocation(),Sound.BLOCK_NOTE_BLOCK_PLING,1,1);Bukkit.getScheduler().runTaskLater(this,()->{if(p.isOnline())giveKit(p,kit);},20L);}
 void giveKit(Player p,String kit){String rs=kit;if(getConfig().contains("kits."+kit+".random-rewards"))rs=roll("kits."+kit+".random-rewards");if(getConfig().getBoolean("kits."+kit+".owner-set",false)||getConfig().getBoolean("reward-sets."+rs+".owner-set",false))ownerSet(p);List<String> cmds=new ArrayList<>(getConfig().getStringList("kits."+kit+".rewards"));cmds.addAll(getConfig().getStringList("reward-sets."+rs+".rewards"));for(String cmd:cmds)Bukkit.dispatchCommand(Bukkit.getConsoleSender(),cmd.replace("%player%",p.getName()));p.playSound(p.getLocation(),Sound.ENTITY_PLAYER_LEVELUP,1,1);p.sendMessage(msg("opened").replace("%kit%",rs));}
 boolean blocked(Player p){for(String w:getConfig().getStringList("blocked-worlds"))if(p.getWorld().getName().equalsIgnoreCase(w))return true;return false;}List<String> weeklyLore(Player p){long cd=getConfig().getLong("settings.cooldown-seconds")*1000L,last=data.getLong(path(p.getName())+".lastWeekly",0),left=cd-(System.currentTimeMillis()-last);String st=last<=0||left<=0?"&aDostępny":"&cZa "+time(left);List<String> out=new ArrayList<>();for(String s:getConfig().getStringList("weekly.lore"))out.add(s.replace("%status%",st));return out;}
 void fill(Inventory inv){ItemStack f=named(mat(getConfig().getString("gui.filler"))," ");for(int i=0;i<inv.getSize();i++)inv.setItem(i,f);}ItemStack action(Material m,String n,List<String> lore,String a){ItemStack it=named(m,n);ItemMeta meta=it.getItemMeta();List<String> l=new ArrayList<>();for(String s:lore)l.add(color(s));meta.setLore(l);meta.getPersistentDataContainer().set(actionKey,PersistentDataType.STRING,a);it.setItemMeta(meta);return it;}
 ItemStack keyItem(String key,int amount){ItemStack it=new ItemStack(mat(getConfig().getString("key-item.material")),Math.max(1,amount));ItemMeta meta=it.getItemMeta();meta.setDisplayName(color(getConfig().getString("key-item.name").replace("%key_name%",display(key))));List<String> l=new ArrayList<>();for(String s:getConfig().getStringList("key-item.lore"))l.add(color(s.replace("%key_name%",display(key)).replace("%key%",key)));meta.setLore(l);meta.getPersistentDataContainer().set(keyKey,PersistentDataType.STRING,key);it.setItemMeta(meta);return it;}
 boolean takeKey(Player p,String key){if(getKeys(p.getName(),key)>0){setKeys(p.getName(),key,getKeys(p.getName(),key)-1);return true;}ItemStack[] c=p.getInventory().getContents();for(int i=0;i<c.length;i++)if(key.equals(keyFrom(c[i]))){if(c[i].getAmount()<=1)p.getInventory().setItem(i,null);else c[i].setAmount(c[i].getAmount()-1);return true;}return false;}int total(Player p,String k){return getKeys(p.getName(),k)+countPhys(p,k);}int countPhys(Player p,String k){int c=0;for(ItemStack it:p.getInventory().getContents())if(k.equals(keyFrom(it)))c+=it.getAmount();return c;}String keyFrom(ItemStack it){return it!=null&&it.hasItemMeta()?it.getItemMeta().getPersistentDataContainer().get(keyKey,PersistentDataType.STRING):null;}
 String roll(String path){ConfigurationSection sec=getConfig().getConfigurationSection(path);if(sec==null)return "klasyczny";int total=0;for(String k:sec.getKeys(false))total+=Math.max(0,sec.getInt(k));int r=new Random().nextInt(Math.max(1,total))+1,c=0;for(String k:sec.getKeys(false)){c+=Math.max(0,sec.getInt(k));if(r<=c)return norm(k);}return "klasyczny";}
 void ownerSet(Player p){p.getInventory().addItem(enchant(Material.NETHERITE_HELMET,"&b&lHełm MILEKZ",new String[][]{{"protection","4"},{"respiration","3"},{"aqua_affinity","1"},{"thorns","3"},{"unbreaking","3"},{"mending","1"}}));p.getInventory().addItem(enchant(Material.NETHERITE_CHESTPLATE,"&b&lNapierśnik MILEKZ",new String[][]{{"protection","4"},{"thorns","3"},{"unbreaking","3"},{"mending","1"}}));p.getInventory().addItem(enchant(Material.NETHERITE_LEGGINGS,"&b&lSpodnie MILEKZ",new String[][]{{"protection","4"},{"thorns","3"},{"unbreaking","3"},{"mending","1"}}));p.getInventory().addItem(enchant(Material.NETHERITE_BOOTS,"&b&lButy MILEKZ",new String[][]{{"protection","4"},{"feather_falling","4"},{"depth_strider","3"},{"soul_speed","3"},{"thorns","3"},{"unbreaking","3"},{"mending","1"}}));p.getInventory().addItem(enchant(Material.NETHERITE_SWORD,"&c&lMieczyk",new String[][]{{"sharpness","5"},{"looting","3"},{"fire_aspect","2"},{"sweeping_edge","3"},{"knockback","2"},{"unbreaking","3"},{"mending","1"}}));p.getInventory().addItem(enchant(Material.BOW,"&e&lŁuk Boga",new String[][]{{"power","5"},{"punch","2"},{"flame","1"},{"infinity","1"},{"unbreaking","3"},{"mending","1"}}));}
 ItemStack enchant(Material m,String n,String[][] e){ItemStack it=named(m,n);for(String[] x:e){Enchantment en=Enchantment.getByKey(NamespacedKey.minecraft(x[0]));if(en!=null)it.addUnsafeEnchantment(en,Integer.parseInt(x[1]));}return it;}int getKeys(String p,String k){return data.getInt(path(p)+".keys."+norm(k),0);}void setKeys(String p,String k,int a){data.set(path(p)+".keys."+norm(k),Math.max(0,a));saveData();}String display(String k){return getConfig().getString("keys."+norm(k)+".display",k);}String path(String p){return "players."+p.toLowerCase(Locale.ROOT);}String norm(String s){return s==null?"":s.toLowerCase(Locale.ROOT);}int parse(String s){try{return Math.max(1,Integer.parseInt(s));}catch(Exception e){return 1;}}ItemStack named(Material m,String n){ItemStack it=new ItemStack(m);ItemMeta meta=it.getItemMeta();meta.setDisplayName(color(n));it.setItemMeta(meta);return it;}Material mat(String s){try{return Material.valueOf(s.toUpperCase(Locale.ROOT));}catch(Exception e){return Material.STONE;}}String msg(String k){return color(getConfig().getString("messages.prefix","")+getConfig().getString("messages."+k,""));}String color(String s){return s==null?"":ChatColor.translateAlternateColorCodes('&',s);}String time(long ms){long s=Math.max(0,ms/1000),d=s/86400;s%=86400;long h=s/3600;s%=3600;long m=s/60;if(d>0)return d+"d "+h+"h";if(h>0)return h+"h "+m+"m";return Math.max(1,m)+"m";}void loadData(){dataFile=new File(getDataFolder(),"data.yml");if(!dataFile.exists())try{getDataFolder().mkdirs();dataFile.createNewFile();}catch(IOException e){e.printStackTrace();}data=YamlConfiguration.loadConfiguration(dataFile);}void saveData(){try{data.save(dataFile);}catch(IOException e){e.printStackTrace();}}
}